// ─── Normalise the incoming payload ───────────────────────────────────────
// Reads from $input.first().json.query

const query = $input.first().json.query ?? {};

const sessionId = query.message
               ?? query.sessionId
               ?? query.session_id
               ?? query.chatId
               ?? 'default-session';

const chatInput = query.message
               ?? query.chatInput
               ?? query.text
               ?? query.input
               ?? '';

const timestamp = query.timestamp
               ?? new Date().toISOString();

const action = query.action ?? 'sendMessage';

return [{ json: { sessionId, chatInput, timestamp, action } }];
